# apply_v7_1_fact_memory_patch.py
# 用法：放到 ugai_agent_langgraph_v0 根目录运行：
# python apply_v7_1_fact_memory_patch.py

from pathlib import Path
import json
import py_compile
import textwrap
import base64
import zlib

DATA = ""

def load_files():
    raw = zlib.decompress(base64.b64decode(DATA.encode("ascii"))).decode("utf-8")
    return json.loads(raw)

def write_clean(path, content):
    path.parent.mkdir(parents=True, exist_ok=True)
    clean = textwrap.dedent(content).lstrip()
    path.write_text(clean, encoding="utf-8")

def main():
    root = Path.cwd()

    if not (root / "config.json").exists():
        raise FileNotFoundError("找不到 config.json。请把脚本放到 ugai_agent_langgraph_v0 根目录运行。")

    files = load_files()

    for rel, content in files.items():
        path = root / rel
        write_clean(path, content)
        print("[OK] 写入", rel)

    config_path = root / "config.json"
    cfg = json.loads(config_path.read_text(encoding="utf-8"))

    fact = cfg.setdefault("fact_memory", {})
    fact["enabled"] = True
    fact["fact_file"] = fact.get("fact_file", "memory_runtime/fact_memory.json")
    fact["prompt_fact_limit"] = int(fact.get("prompt_fact_limit", 6))

    event_log = cfg.setdefault("event_log", {})
    event_log["enabled"] = True
    event_log["event_file"] = event_log.get("event_file", "memory_runtime/event_log.jsonl")

    reflection = cfg.setdefault("reflection", {})
    reflection["enabled"] = True
    reflection["auto_enabled"] = bool(reflection.get("auto_enabled", False))

    config_path.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    print("[OK] 更新 config.json fact_memory")

    for rel in files:
        py_compile.compile(str(root / rel), doraise=True)
        print("[OK] 语法检查", rel)

    print("")
    print("UGAI Agent v7.1 Fact Memory 升级完成。")
    print("")
    print("重启：python main_qq.py")
    print("")
    print("测试：")
    print("1. /fact_add 主人喜欢默认简短、流畅的回复")
    print("2. /facts")
    print("3. 正常问一句相关内容")
    print("4. /debug 查看 fact_memory_items_used")
    print("5. /events 后可用 /fact_from_event 事件ID 内容")

if __name__ == "__main__":
    main()
